import numpy as np
import logging,os,pickle,json
from datetime import datetime
from collections import defaultdict
log=logging.getLogger(__name__)

class DynamicEnsemble:
    """
    Dynamic Weighted Ensemble:
    - Weights based on recent performance
    - Context-aware (regime specific)
    - Auto-adjusts every 20 trades

    Models:
    1. ML (GradientBoosting) - general
    2. RL Agent - sequential decisions
    3. Transformer - pattern recognition
    4. Meta-labeling - signal quality
    5. MMT - multi-modal
    6. CRL - risk-aware
    """

    def __init__(self,symbol):
        self.symbol=symbol

        # Default weights per model
        self.base_weights={
            'ml':0.25,
            'rl':0.15,
            'transformer':0.20,
            'meta':0.15,
            'mmt':0.15,
            'crl':0.10
        }

        # Context weights per regime
        self.regime_weights={
            'TRENDING_UP':{
                'ml':0.20,
                'rl':0.25,      # RL good at trends
                'transformer':0.25,  # Transformer sees patterns
                'meta':0.15,
                'mmt':0.10,
                'crl':0.05
            },
            'TRENDING_UP_HV':{
                'ml':0.15,
                'rl':0.30,      # RL excels in strong trends
                'transformer':0.25,
                'meta':0.15,
                'mmt':0.10,
                'crl':0.05
            },
            'TRENDING_DOWN':{
                'ml':0.20,
                'rl':0.25,
                'transformer':0.25,
                'meta':0.15,
                'mmt':0.10,
                'crl':0.05
            },
            'RANGING':{
                'ml':0.30,      # ML good at ranging
                'rl':0.10,      # RL bad at ranging
                'transformer':0.15,
                'meta':0.20,    # Meta important in ranging
                'mmt':0.15,
                'crl':0.10
            },
            'VOLATILE':{
                'ml':0.15,
                'rl':0.10,
                'transformer':0.20,
                'meta':0.20,
                'mmt':0.15,
                'crl':0.20     # CRL most important in volatile!
            }
        }

        # Performance tracking per model per regime
        self.performance=defaultdict(lambda:defaultdict(list))
        self.dynamic_weights={}
        self._load_weights()

    def _load_weights(self):
        """Load saved dynamic weights"""
        try:
            fname=f'ml_models/{self.symbol}_ensemble_weights.json'
            if os.path.exists(fname):
                self.dynamic_weights=json.load(open(fname))
                log.info(f'[ENS] {self.symbol} weights loaded!')
        except:pass

    def _save_weights(self):
        """Save dynamic weights"""
        try:
            fname=f'ml_models/{self.symbol}_ensemble_weights.json'
            json.dump(self.dynamic_weights,open(fname,'w'),indent=2)
        except:pass

    def get_weights(self,regime):
        """Get current weights for regime"""
        try:
            # Check dynamic weights first
            key=f'{regime}_weights'
            if key in self.dynamic_weights:
                return self.dynamic_weights[key]
            # Use regime-specific defaults
            if regime in self.regime_weights:
                return self.regime_weights[regime]
            return self.base_weights
        except:
            return self.base_weights

    def update_weights(self,regime,model,outcome):
        """Update model weight based on outcome"""
        try:
            self.performance[regime][model].append(outcome)

            # Recalculate after 20 samples
            if len(self.performance[regime][model])%20==0:
                self._recalculate_weights(regime)
        except Exception as e:
            log.error(f'[ENS] Update error: {e}')

    def _recalculate_weights(self,regime):
        """Recalculate weights based on performance"""
        try:
            models=list(self.base_weights.keys())
            performance_scores={}

            for model in models:
                outcomes=self.performance[regime][model]
                if len(outcomes)<10:
                    # Use default
                    default=self.regime_weights.get(regime,self.base_weights)
                    performance_scores[model]=default.get(model,0.15)
                    continue

                # Calculate win rate
                wr=sum(outcomes)/len(outcomes)
                # Recent performance (last 20)
                recent=outcomes[-20:]
                recent_wr=sum(recent)/len(recent)
                # Combined score
                score=wr*0.4+recent_wr*0.6
                performance_scores[model]=score

            # Normalize weights
            total=sum(performance_scores.values())
            if total>0:
                normalized={m:round(s/total,3) for m,s in performance_scores.items()}
            else:
                normalized=self.base_weights.copy()

            key=f'{regime}_weights'
            self.dynamic_weights[key]=normalized
            self._save_weights()

            log.info(f'[ENS] {self.symbol} {regime} weights updated:')
            for m,w in sorted(normalized.items(),key=lambda x:x[1],reverse=True):
                log.info(f'  {m}: {w:.3f}')

        except Exception as e:
            log.error(f'[ENS] Recalculate error: {e}')

    def combine_predictions(self,predictions,regime,signal):
        """
        Combine model predictions with dynamic weights
        predictions = dict of {model_name: probability}
        """
        try:
            weights=self.get_weights(regime)
            total_weight=0
            weighted_sum=0

            model_details={}
            for model,prob in predictions.items():
                if model in weights:
                    w=weights[model]
                    weighted_sum+=prob*w
                    total_weight+=w
                    model_details[model]={'prob':round(prob,3),'weight':round(w,3)}

            if total_weight==0:
                return 0.5,{}

            final_prob=weighted_sum/total_weight

            # Confidence boost for agreement
            probs=list(predictions.values())
            agreement=sum(1 for p in probs if p>0.5)/len(probs) if probs else 0.5
            if agreement>0.8:  # 80%+ models agree
                final_prob=min(final_prob*1.1,0.95)
                log.info(f'[ENS] {self.symbol} HIGH AGREEMENT! {agreement:.0%}')
            elif agreement<0.3:  # Models disagree strongly
                final_prob*=0.8
                log.info(f'[ENS] {self.symbol} LOW AGREEMENT! {agreement:.0%}')

            log.info(f'[ENS] {self.symbol} final={final_prob:.3f} regime={regime}')
            return round(final_prob,3),model_details

        except Exception as e:
            log.error(f'[ENS] Combine error: {e}')
            return 0.5,{}

    def get_ensemble_prob(self,symbol,signal,features,
                         ml_prob,meta_prob,mmt_prob,crl_ok):
        """
        Main function: Get ensemble probability
        """
        try:
            regime=signal.get('regime','RANGING')

            # Collect all model predictions
            predictions={
                'ml':ml_prob,
                'meta':meta_prob,
                'mmt':mmt_prob,
                'crl':0.7 if crl_ok else 0.3,
            }

            # Try to get RL prediction
            try:
                rl_fname=f'ml_models/{symbol}_v31_rl.pkl'
                if os.path.exists(rl_fname):
                    rl_agent=pickle.load(open(rl_fname,'rb'))
                    if hasattr(rl_agent,'predict'):
                        rl_prob=float(rl_agent.predict(np.array(features[:30]).reshape(1,-1))[0])
                        predictions['rl']=rl_prob
                    else:
                        predictions['rl']=0.5
                else:
                    predictions['rl']=0.5
            except:
                predictions['rl']=0.5

            # Try transformer prediction
            try:
                tf_fname=f'ml_models/{symbol}_v31_transformer.pkl'
                if os.path.exists(tf_fname):
                    tf_model=pickle.load(open(tf_fname,'rb'))
                    if hasattr(tf_model,'predict_proba'):
                        tf_prob=float(tf_model.predict_proba(
                            np.array(features[:30]).reshape(1,-1))[0][1])
                        predictions['transformer']=tf_prob
                    else:
                        predictions['transformer']=0.5
                else:
                    predictions['transformer']=0.5
            except:
                predictions['transformer']=0.5

            # Combine with dynamic weights
            final_prob,details=self.combine_predictions(predictions,regime,signal)
            return final_prob,details

        except Exception as e:
            log.error(f'[ENS] Error: {e}')
            return ml_prob,{}  # Fallback to ML prob

    def record_outcome(self,regime,predictions,outcome):
        """Record outcome for weight updates"""
        try:
            for model,prob in predictions.items():
                model_correct=1 if (prob>=0.5)==(outcome==1) else 0
                self.update_weights(regime,model,model_correct)
        except Exception as e:
            log.error(f'[ENS] Record error: {e}')


# Global instances
_ensemble_engines={}

def get_ensemble(symbol):
    if symbol not in _ensemble_engines:
        _ensemble_engines[symbol]=DynamicEnsemble(symbol)
    return _ensemble_engines[symbol]

def get_dynamic_ensemble_prob(symbol,signal,features,
                              ml_prob,meta_prob,mmt_prob,crl_ok):
    """Main function"""
    eng=get_ensemble(symbol)
    return eng.get_ensemble_prob(symbol,signal,features,
                                 ml_prob,meta_prob,mmt_prob,crl_ok)

v31_token_updater.py:
"""
V31 Token Updater - Production Grade
Updates MCX futures tokens monthly
Run on 1st of every month or after expiry
"""
import requests,json,logging,shutil,re,os
from datetime import datetime
log=logging.getLogger(__name__)

DRY_RUN=False  # Set True to test without writing

def get_date(s):
    """Safe expiry date parser"""
    try:
        m=re.search(r'(\d{2})([A-Z]{3})(\d{2})FUT',s['symbol'])
        if m:
            return datetime.strptime(
                f"{m.group(1)}{m.group(2)}{m.group(3)}",'%d%b%y')
    except Exception as e:
        log.debug(f"Date parse failed: {s['symbol']}: {e}")
    return datetime.max

def download_master(retries=3):
    """Download Angel One master with retry"""
    url='https://margincalculator.angelbroking.com/OpenAPI_File/files/OpenAPIScripMaster.json'
    for attempt in range(retries):
        try:
            log.info(f'Downloading master (attempt {attempt+1})...')
            data=requests.get(url,timeout=30).json()
            log.info(f'Downloaded {len(data)} instruments')
            return data
        except Exception as e:
            log.warning(f'Attempt {attempt+1} failed: {e}')
            if attempt<retries-1:
                import time;time.sleep(3)
    return None

def update_mcx_tokens(dry_run=DRY_RUN):
    """Update MCX futures tokens safely"""

    # Step 1: Download master
    data=download_master()
    if not data:
        log.error('Failed to download master!')
        return {}

    # Step 2: Find nearest futures
    MCX_INSTRUMENTS=['CRUDEOIL','GOLDM','SILVERM','NATURALGAS']
    tokens={}

    for inst in MCX_INSTRUMENTS:
        futures=[d for d in data
                if d.get('exch_seg')=='MCX'
                and d.get('symbol','').startswith(inst)
                and not d['symbol'].endswith(('CE','PE'))
                and 'FUT' in d.get('symbol','')]

        if not futures:
            log.warning(f'{inst}: No futures found!')
            continue

        # Sort by nearest expiry
        futures.sort(key=get_date)
        nearest=futures[0]
        tokens[inst]={
            'token':nearest['token'],
            'symbol':nearest['symbol'],
            'lotsize':nearest.get('lotsize',1),
            'exchange':'MCX'
        }
        log.info(f'{inst}: {nearest["symbol"]} token={nearest["token"]}')

    # Step 3: Validate
    if not tokens:
        log.error('No tokens found - aborting!')
        return {}

    # Step 4: Backup before modify!
    if not dry_run:
        shutil.copy('angel_feed.py','angel_feed_backup.py')
        log.info('Backup created: angel_feed_backup.py')

    # Step 5: Update angel_feed.py safely
    content=open('angel_feed.py').read()
    for inst,info in tokens.items():
        # Safe precise regex
        old_pattern=rf"'{inst}':\s*\{{[^}}]*\}}"
        new_val=f"'{inst}':  {{'token':'{info['token']}','exchange':'MCX'}}  # {info['symbol']}"
        new_content=re.sub(old_pattern,new_val,content)
        if new_content==content:
            log.warning(f'{inst}: Pattern not found in angel_feed.py!')
        else:
            content=new_content
            log.info(f'{inst}: Updated in angel_feed.py')

    if dry_run:
        log.info('DRY RUN - not writing files')
        print('DRY RUN complete!')
    else:
        open('angel_feed.py','w').write(content)
        json.dump(tokens,open('mcx_tokens.json','w'),indent=2)
        log.info('✅ angel_feed.py + mcx_tokens.json updated!')

    # Step 6: Verify
    print('\n=== Token Update Summary ===')
    for inst,info in tokens.items():
        print(f'{inst:<12}: {info["symbol"]} token={info["token"]}')
    print(f'\nTotal: {len(tokens)}/4 updated')

    return tokens

if __name__=='__main__':
    logging.basicConfig(level=logging.INFO,
                       format='%(asctime)s %(levelname)s %(message)s')
    tokens=update_mcx_tokens()
    if tokens:
        print('\n✅ Token update successful!')
    else:
        print('\n❌ Token update failed!')

v31_signal_manager.py:
"""
V31 Signal Manager V2 - Production Grade
Session-based trade control with direction tracking
All critical fixes applied
"""
import logging,json,os
from datetime import datetime,time,timedelta
log=logging.getLogger(__name__)

# ============================================================
# SESSION DEFINITIONS
# ============================================================
NSE_SESSIONS=[
    {'name':'MORNING',  'start':time(9,30),  'end':time(13,30)},
    {'name':'AFTERNOON','start':time(13,30), 'end':time(15,0)},
]
MCX_SESSIONS=[
    {'name':'EVENING',  'start':time(15,30), 'end':time(18,0)},
    {'name':'NIGHT',    'start':time(18,0),  'end':time(23,0)},
]

MCX_INST=['CRUDEOIL','GOLDM','SILVERM','NATURALGAS']
INDEX_INST=['NIFTY','BANKNIFTY','FINNIFTY','MIDCPNIFTY','SENSEX']

# ✅ Fix 2: Clear direction mapping
SELL_TYPES=('SELL','SELL_CE','SELL_PE','STRADDLE','PE')
BUY_TYPES=('BUY','CE','CALL')

MAX_DAILY_TRADES=8       # Per instrument daily cap
COOLDOWN_SECS=300        # 5 min between trades
SELL_LOCK_TIMEOUT=1800   # 30 min sell lock auto-release

STATE_FILE='signal_manager_state.json'

# ============================================================
# SIGNAL MANAGER
# ============================================================
class SignalManager:
    def __init__(self):
        self.state={}          # {instrument:{session:{BUY:0,SELL:0}}}
        self.active_sells={}   # {instrument: strategy_type}
        self.sell_lock_time={} # {instrument: datetime}
        self.last_trade_time={}# {instrument: datetime} cooldown
        self.date=None

        # Position state manager
        self.positions={}      # {instrument: {side,entry_price,status}}
        self.last_exit_time={} # {instrument: datetime} post-exit cooldown

        # Portfolio Risk Engine
        self.daily_loss=0
        self.max_daily_loss=-7000   # Rs.3000 max daily loss
        self.max_trades_per_day=8
        self.trade_count=0
        self.trading_enabled=True
        self.kill_switch=False

        # AI Trade Manager stats
        self.stats={'wins':0,'losses':0}

        self.load_state()

    # ============================================================
    # POSITION STATE MANAGER
    # ============================================================
    def has_active_position(self,inst):
        """Check if instrument has open position"""
        return inst in self.positions and self.positions[inst].get('status')=='OPEN'

    def get_position_side(self,inst):
        """Get current position side (CE/PE/BUY/SELL)"""
        if self.has_active_position(inst):
            return self.positions[inst].get('side')
        return None

    def open_position(self,inst,side,price):
        """Record new position"""
        self.positions[inst]={
            'side':side,
            'entry_price':price,
            'status':'OPEN',
            'open_time':datetime.now().isoformat()
        }
        log.info(f'[SM] Position opened: {inst} {side} @ Rs.{price}')

    def close_position(self,inst):
        """Close position and start cooldown"""
        if inst in self.positions:
            self.positions[inst]['status']='CLOSED'
            self.last_exit_time[inst]=datetime.now()
            log.info(f'[SM] Position closed: {inst}')

    def cooldown_active(self,inst,secs=300):
        """Check if post-exit cooldown active (5 mins)"""
        if inst not in self.last_exit_time:return False
        elapsed=(datetime.now()-self.last_exit_time[inst]).seconds
        return elapsed<secs

    def _is_opposite_side(self,current_side,new_direction):
        """Check if new signal opposes current position"""
        buy_types=('BUY','CE','CALL')
        sell_types=('SELL','PE','PUT')
        current_is_buy=current_side in buy_types or 'CE' in str(current_side)
        new_is_buy=new_direction in buy_types
        return current_is_buy != new_is_buy

    def load_state(self):
        try:
            if os.path.exists(STATE_FILE):
                data=json.load(open(STATE_FILE))
                if data.get('date')==datetime.now().strftime('%Y-%m-%d'):
                    self.state=data.get('state',{})
                    self.active_sells=data.get('active_sells',{})
                    self.date=data['date']
                    log.info(f'[SM] Loaded state for {self.date}')
                    return
            self._reset()
        except:
            self._reset()

    def save_state(self):
        try:
            json.dump({
                'date':datetime.now().strftime('%Y-%m-%d'),
                'state':self.state,
                'active_sells':self.active_sells,
            },open(STATE_FILE,'w'))
        except:pass

    def _reset(self):
        self.state={}
        self.active_sells={}
        self.sell_lock_time={}
        self.last_trade_time={}
        self.date=datetime.now().strftime('%Y-%m-%d')
        self.save_state()

    def _get_session(self,instrument):
        """Get current session name"""
        now=datetime.now().time()
        sessions=MCX_SESSIONS if instrument in MCX_INST else NSE_SESSIONS
        for s in sessions:
            if s['start']<=now<s['end']:
                return s['name']
        return None

    def _get_limits(self,score):
        """✅ Fix 1: Score-based limits"""
        if score>=28:
            return {'BUY':2,'SELL':2}  # High conviction
        elif score>=25:
            return {'BUY':2,'SELL':1}
        elif score>=20:
            return {'BUY':1,'SELL':1}
        elif score>=15:
            return {'BUY':1,'SELL':1}  # Allow lower scores!
        else:
            return {'BUY':0,'SELL':0}  # Too low!

    def _get_daily_total(self,instrument):
        """Get total trades today for instrument"""
        total=0
        for sess in self.state.get(instrument,{}).values():
            total+=sess.get('BUY',0)+sess.get('SELL',0)
        return total


    def _check_direction_bias(self,instrument,dir_key):
        """Check if direction flip detected (chop filter)"""
        opposite='BUY' if dir_key=='SELL' else 'SELL'
        inst_state=self.state.get(instrument,{})
        total_opposite=sum(s.get(opposite,0) for s in inst_state.values())
        total_same=sum(s.get(dir_key,0) for s in inst_state.values())
        if total_same>=1 and total_opposite>=1:
            log.info(f'[SM] {instrument} direction flip: {opposite}:{total_opposite} {dir_key}:{total_same}')
            return True
        return False

    def _auto_release_sell_lock(self,instrument):
        """✅ Fix 3: Auto-release sell lock after timeout"""
        if instrument in self.sell_lock_time:
            elapsed=(datetime.now()-self.sell_lock_time[instrument]).seconds
            if elapsed>SELL_LOCK_TIMEOUT:
                log.info(f'[SM] Auto-releasing sell lock for {instrument} after {elapsed}s')
                self.release_sell_lock(instrument)

    # ============================================================
    # PORTFOLIO RISK ENGINE
    # ============================================================
    def win_rate(self):
        """Calculate current win rate"""
        total=self.stats['wins']+self.stats['losses']
        if total==0:return 0.5
        return self.stats['wins']/total

    def get_adaptive_flip_score(self):
        """Adjust flip threshold based on performance"""
        wr=self.win_rate()
        if wr<0.40:  return 32  # Losing → very strict
        elif wr>0.60:return 27  # Winning → aggressive
        else:        return 29  # Normal

    def get_lot_size(self,score):
        """Dynamic lot sizing based on signal score"""
        if score>=30: return 2  # High confidence = 2 lots
        elif score>=25:return 1  # Normal = 1 lot
        else:          return 0  # Skip weak signals

    def update_pnl(self,pnl):
        """Update daily P&L and stats"""
        self.daily_loss+=pnl
        if pnl>0:
            self.stats['wins']+=1
        else:
            self.stats['losses']+=1
        log.info(f'[RM] Daily P&L: Rs.{self.daily_loss:,.0f} '
                f'WR={self.win_rate():.0%} '
                f'W:{self.stats["wins"]} L:{self.stats["losses"]}')
        # Alert if near limit
        if self.daily_loss<=self.max_daily_loss*0.7:
            try:
                from v31_notify import send
                send(f'⚠️ Risk Alert! Daily loss: Rs.{self.daily_loss:,.0f} / Limit: Rs.{self.max_daily_loss:,.0f}')



            except:pass

    def reset_daily(self):
        """Reset daily counters at market open"""
        self.daily_loss=0
        self.trade_count=0
        self.trading_enabled=True
        self.stats={'wins':0,'losses':0}
        log.info('[RM] Daily reset! Trading enabled.')

    def dynamic_hold_time(self,instrument,atr=None):
        """Dynamic hold time based on volatility"""
        try:
            if atr is None:return 1800
            if atr>2:  return 1200  # 20 min (high volatility)
            elif atr>1:return 1800  # 30 min (normal)
            else:      return 2400  # 40 min (slow market)
        except:return 1800

    def flip_score(self,instrument,direction,signal=None,score=0):
        """
        5-factor flip scoring system
        Uses existing signal data - no extra API calls!
        Returns: (allowed, flip_score, reason)
        """
        if signal is None:
            return False,0,'No signal data'

        fs=0
        reasons=[]

        # 1. Signal score quality (max 2pts)
        if score>=29:
            fs+=2; reasons.append(f'score={score}✅')
        elif score>=27:
            fs+=1; reasons.append(f'score={score}⚠️')
        else:
            reasons.append(f'score={score}❌')

        # 2. SL type quality (max 2pts)
        sl_type=signal.get('sl_type','')
        if 'FVG' in sl_type:
            fs+=2; reasons.append('FVG✅')
        elif 'OB' in sl_type:
            fs+=1; reasons.append('OB⚠️')
        else:
            reasons.append(f'{sl_type}❌')

        # 3. Trend aligned (1pt)
        if signal.get('trend_aligned',False):
            fs+=1; reasons.append('trend✅')
        else:
            reasons.append('trend❌')

        # 4. Market regime (max 2pts, min -1pt)
        regime=signal.get('regime','RANGING')
        if 'TRENDING' in regime:
            fs+=2; reasons.append(f'{regime}✅')
        elif 'RANGING' in regime:
            fs-=1; reasons.append(f'{regime}❌')
        else:
            fs+=1; reasons.append(f'{regime}⚠️')

        # 5. Liquidity sweep (1pt)
        liq=signal.get('liq_type','')
        if 'SWEEP' in liq:
            fs+=1; reasons.append('SWEEP✅')
        elif 'EQUAL' in liq:
            fs+=0; reasons.append('EQUAL⚠️')

        # Bonus: Gamma boost
        if signal.get('gamma_boost',0)>0:
            fs+=1; reasons.append('GAMMA✅')

        allowed=fs>=5
        reason=f'FlipScore:{fs}/8 [{",".join(reasons)}]'
        log.info(f'[SM] {instrument} flip check: {reason}')
        return allowed,fs,reason

    # Keep for backward compatibility
    def volume_spike(self,instrument,signal=None):
        return signal is not None

    def market_regime_ok(self,instrument,signal=None):
        if signal is None:return False
        return signal.get('regime','RANGING') not in ('RANGING','CHOPPY')

    def mtf_aligned(self,instrument,direction,signal=None):
        if signal is None:return False
        return signal.get('trend_aligned',False)

    def can_trade(self,instrument,direction,score=18,strategy_type='DIRECT',atr=None,signal=None):
        """
        7-step check in CORRECT order:
        1.Session 2.Cooldown 3.DailyCap 4.SellLock 5.DirFlip 6.Score 7.Limit
        """
        now=datetime.now()
        dir_key='SELL' if direction in SELL_TYPES else 'BUY'

        # 0. KILL SWITCH
        if self.kill_switch:
            return False,'System paused (kill switch active)'

        # 0a. DAILY LOSS LIMIT
        if self.daily_loss<=self.max_daily_loss:
            self.trading_enabled=False
            try:
                from v31_notify import send
                send(f'🚨 Daily loss limit hit!\n'
                     f'Loss: Rs.{self.daily_loss:,.0f}\n'
                     f'Trading STOPPED for today!')
            except:pass
            return False,f'Daily loss limit hit (Rs.{self.daily_loss:,.0f})'

        # 0b. TRADING ENABLED CHECK
        if not self.trading_enabled:
            return False,'Trading disabled'

        # 0c. TRADE COUNT LIMIT
        if self.trade_count>=self.max_trades_per_day:
            return False,f'Max trades reached ({self.trade_count}/{self.max_trades_per_day})'

        # 0. POST-EXIT COOLDOWN
        if self.cooldown_active(instrument):
            return False,f'Post-exit cooldown active (5 mins)'

        # 0b. POSITION CONFLICT CHECK
        if self.has_active_position(instrument):
            current_side=self.get_position_side(instrument)
            is_opposite=self._is_opposite_side(current_side,dir_key)
            if is_opposite:
                if score>=27:
                    # High score flip - close old position first
                    log.info(f'[SM] {instrument} FLIP allowed (score={score}) closing {current_side}')
                    self.close_position(instrument)
                else:
                    return False,f'Position conflict: {current_side} active, need score>=27 to flip (got {score})'
            else:
                # Same direction - check session limit normally
                pass

        # 1. SESSION CHECK
        session=self._get_session(instrument)
        if not session:
            return False,f'Outside session ({instrument})'

        # 2. COOLDOWN CHECK (trade cooldown)
        if instrument in self.last_trade_time:
            elapsed=(now-self.last_trade_time[instrument]).seconds
            if elapsed<COOLDOWN_SECS:
                return False,f'Cooldown: {COOLDOWN_SECS-elapsed}s remaining'

        # 2b. POST-EXIT COOLDOWN (after early exit/loss protection)
        if instrument in self.last_exit_time:
            _exit_elapsed=(now-self.last_exit_time[instrument]).seconds
            _exit_cooldown=300  # 5 mins after early exit
            if _exit_elapsed<_exit_cooldown:
                _remaining=_exit_cooldown-_exit_elapsed
                return False,f'Post-exit cooldown: {_remaining}s remaining'

        # 3. DAILY CAP
        if self._get_daily_total(instrument)>=MAX_DAILY_TRADES:
            return False,f'Daily cap reached ({self._get_daily_total(instrument)}/{MAX_DAILY_TRADES})'

        # 4. SELL LOCK
        self._auto_release_sell_lock(instrument)
        if dir_key=='SELL' and instrument in self.active_sells:
            active=self.active_sells[instrument]
            if active!=strategy_type:
                return False,f'Sell lock: {active} active'

        # 5. DIRECTION FLIP
        flip=self._check_direction_bias(instrument,dir_key)
        if flip and score<25:
            return False,f'Direction flip: need score>=25 (got {score})'

        # 6. SCORE FILTER
        if score>=28:
            limits={'BUY':3,'SELL':2}  # Boost (not bypass!)
            log.info(f'[SM] {instrument} HIGH SCORE BOOST ({score})')
        else:
            limits=self._get_limits(score)
        if limits[dir_key]==0:
            return False,f'Score {score} too low for {dir_key} (need>=20)'

        # 7. SESSION LIMIT
        inst_state=self.state.get(instrument,{})
        sess_state=inst_state.get(session,{'BUY':0,'SELL':0})
        current=sess_state.get(dir_key,0)
        max_allowed=limits[dir_key]
        if current>=max_allowed:
            return False,f'{dir_key} limit ({current}/{max_allowed}) in {session}'

        # ALLOW
        log.info(f'[SM] {instrument}|{session}|{dir_key}|{current+1}/{max_allowed}|Score:{score}')
        return True,f'Allowed ({current+1}/{max_allowed}) in {session}'

    def record_trade(self,instrument,direction,strategy_type='DIRECT'):
        """Record trade taken"""
        session=self._get_session(instrument)
        if not session:return

        if instrument not in self.state:
            self.state[instrument]={}
        if session not in self.state[instrument]:
            self.state[instrument][session]={'BUY':0,'SELL':0}

        dir_key='SELL' if direction in SELL_TYPES else 'BUY'
        self.state[instrument][session][dir_key]+=1

        # Lock sell strategy + record time
        if dir_key=='SELL':
            self.active_sells[instrument]=strategy_type
            self.sell_lock_time[instrument]=datetime.now()

        # ✅ Fix 5: Record for cooldown
        self.last_trade_time[instrument]=datetime.now()

        # Increment trade count
        self.trade_count+=1
        log.info(f'[RM] Trade count: {self.trade_count}/{self.max_trades_per_day}')

        # Open position tracker
        self.open_position(instrument,dir_key,0)  # price updated by exit monitor

        total=self._get_daily_total(instrument)
        log.info(f'[SM] Recorded {instrument} {dir_key} in {session} '
                f'(session:{self.state[instrument][session][dir_key]} daily:{total})')
        self.save_state()

    def release_sell_lock(self,instrument):
        """Release sell lock when position closed"""
        if instrument in self.active_sells:
            del self.active_sells[instrument]
        if instrument in self.sell_lock_time:
            del self.sell_lock_time[instrument]
        log.info(f'[SM] Released sell lock: {instrument}')
        self.save_state()

    def is_in_session(self,instrument):
        return self._get_session(instrument) is not None

    def get_status(self,instrument,direction='BUY'):
        session=self._get_session(instrument)
        if not session:return 'No session'
        dir_key='SELL' if direction in SELL_TYPES else 'BUY'
        sess_state=self.state.get(instrument,{}).get(session,{})
        daily=self._get_daily_total(instrument)
        return f'{sess_state.get(dir_key,0)}/2 in {session} | Daily:{daily}/{MAX_DAILY_TRADES}'

    def get_session_summary(self):
        return {
            'date':self.date,
            'state':self.state,
            'active_sells':list(self.active_sells.keys()),
            'daily_totals':{i:self._get_daily_total(i) for i in self.state}
        }

    def reset_day(self):
        self._reset()
        log.info('[SM] Day reset!')


# Global instance
signal_manager=SignalManager()

v31_oi_pcr.py:
"""
V31 OI & PCR Engine
Fetches NSE option chain data
Provides PCR + OI levels for signal filtering
"""
import json,time,logging
import urllib.request,http.cookiejar
from datetime import datetime

log=logging.getLogger(__name__)

class OIPCREngine:
    def __init__(self):
        self._cache={}
        self._cache_time={}
        self._session=None
        self._last_fetch=0
        self.CACHE_TTL=180  # 3 mins

    def _create_session(self):
        """Create NSE session with cookies"""
        try:
            cj=http.cookiejar.CookieJar()
            opener=urllib.request.build_opener(
                urllib.request.HTTPCookieProcessor(cj))
            opener.addheaders=[
                ('User-Agent','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'),
                ('Accept','text/html,application/json,*/*'),
                ('Accept-Language','en-US,en;q=0.9'),
                ('Referer','https://www.nseindia.com'),
            ]
            # Hit homepage to get cookies
            opener.open('https://www.nseindia.com',timeout=5)
            time.sleep(1)
            self._session=opener
            log.info('[OI] NSE session created ✅')
            return True
        except Exception as e:
            log.warning(f'[OI] Session error: {e}')
            return False

    def fetch_angel_oi(self,symbol='NIFTY'):
        """Fetch OI data from Angel One directly"""
        try:
            from v31_angel_trader import angel_trader
            import json
            if not angel_trader.connected:
                return {}

            # Try getOIData
            r=angel_trader.obj.getOIData(symbol)
            if isinstance(r,str):
                try:r=json.loads(r)
                except:return {}
            if isinstance(r,dict) and r.get('data'):
                log.info(f'[OI] {symbol} Angel OI data received ✅')
                return r

            # Try oIBuildup
            r=angel_trader.obj.oIBuildup(symbol)
            if isinstance(r,str):
                try:r=json.loads(r)
                except:return {}
            if isinstance(r,dict) and r.get('data'):
                return r
        except Exception as e:
            log.debug(f'[OI] Angel OI error: {e}')
        return {}

    def fetch_option_chain(self,symbol='NIFTY',is_stock=False):
        """Fetch option chain - try Angel first, then NSE"""
        # Check cache
        now=time.time()
        if symbol in self._cache:
            if now-self._cache_time.get(symbol,0)<self.CACHE_TTL:
                return self._cache[symbol]

        # Try Angel One first (more reliable!)
        angel_data=self.fetch_angel_oi(symbol)
        if angel_data:
            self._cache[symbol]=angel_data
            self._cache_time[symbol]=now
            return angel_data

        log.debug(f'[OI] Angel failed, trying NSE...')
        # Check cache
        now=time.time()
        if symbol in self._cache:
            if now-self._cache_time.get(symbol,0)<self.CACHE_TTL:
                return self._cache[symbol]

        # Rate limit
        if now-self._last_fetch<30:
            return self._cache.get(symbol,{})

        # Create session if needed
        if not self._session:
            if not self._create_session():
                return {}

        # Fetch option chain
        for attempt in range(3):
            try:
                if is_stock:
                    url=f'https://www.nseindia.com/api/option-chain-equities?symbol={symbol}'
                else:
                    url=f'https://www.nseindia.com/api/option-chain-indices?symbol={symbol}'

                resp=self._session.open(url,timeout=5)
                data=json.loads(resp.read())
                self._cache[symbol]=data
                self._cache_time[symbol]=now
                self._last_fetch=now
                log.info(f'[OI] {symbol} option chain fetched ✅')
                return data
            except Exception as e:
                log.warning(f'[OI] Fetch attempt {attempt+1} failed: {e}')
                if attempt<2:
                    time.sleep(2*(attempt+1))
                    self._session=None  # Reset session
                    self._create_session()

        return {}

    def get_pcr(self,symbol='NIFTY'):
        """
        Get PCR for symbol
        Returns: (total_pcr, atm_pcr, signal)
        """
        try:
            data=self.fetch_option_chain(symbol)
            if not data:return 1.0,1.0,'NEUTRAL'

            # Total PCR
            filtered=data.get('filtered',{})
            ce_oi=filtered.get('CE',{}).get('totOI',1)
            pe_oi=filtered.get('PE',{}).get('totOI',0)
            total_pcr=pe_oi/max(ce_oi,1)

            # ATM PCR (more accurate!)
            spot=data.get('records',{}).get('underlyingValue',0)
            atm_strike=round(spot/50)*50 if spot>0 else 0
            atm_pcr=total_pcr  # Default

            if atm_strike>0:
                for item in data.get('records',{}).get('data',[]):
                    if item.get('strikePrice')==atm_strike:
                        ce=item.get('CE',{}).get('openInterest',1)
                        pe=item.get('PE',{}).get('openInterest',0)
                        atm_pcr=pe/max(ce,1)
                        break

            # Signal
            if atm_pcr>1.2:signal='BULLISH'
            elif atm_pcr<0.8:signal='BEARISH'
            else:signal='NEUTRAL'

            log.info(f'[OI] {symbol} PCR={total_pcr:.2f} ATM={atm_pcr:.2f} {signal}')
            return total_pcr,atm_pcr,signal
        except Exception as e:
            log.debug(f'[OI] PCR error: {e}')
            return 1.0,1.0,'NEUTRAL'

    def get_max_pain(self,symbol='NIFTY'):
        """Calculate max pain strike"""
        try:
            data=self.fetch_option_chain(symbol)
            if not data:return 0

            strikes={}
            for item in data.get('records',{}).get('data',[]):
                strike=item.get('strikePrice',0)
                ce_oi=item.get('CE',{}).get('openInterest',0)
                pe_oi=item.get('PE',{}).get('openInterest',0)
                strikes[strike]={'ce':ce_oi,'pe':pe_oi}

            if not strikes:return 0

            # Max pain = strike where total loss is minimized
            min_loss=float('inf')
            max_pain=0
            for test_price in strikes:
                total_loss=0
                for strike,(oi) in strikes.items():
                    # CE loss
                    if test_price>strike:
                        total_loss+=oi['ce']*(test_price-strike)
                    # PE loss
                    if test_price<strike:
                        total_loss+=oi['pe']*(strike-test_price)
                if total_loss<min_loss:
                    min_loss=total_loss
                    max_pain=test_price

            log.info(f'[OI] {symbol} max pain={max_pain}')
            return max_pain
        except Exception as e:
            log.debug(f'[OI] Max pain error: {e}')
            return 0

    def get_oi_levels(self,symbol='NIFTY'):
        """Get high OI strikes as S/R levels"""
        try:
            data=self.fetch_option_chain(symbol)
            if not data:return [],[]

            ce_strikes={}
            pe_strikes={}

            for item in data.get('records',{}).get('data',[]):
                strike=item.get('strikePrice',0)
                ce_oi=item.get('CE',{}).get('openInterest',0)
                pe_oi=item.get('PE',{}).get('openInterest',0)
                if ce_oi>0:ce_strikes[strike]=ce_oi
                if pe_oi>0:pe_strikes[strike]=pe_oi

            # Top 3 CE strikes = resistance
            top_ce=sorted(ce_strikes,key=lambda x:-ce_strikes[x])[:3]
            # Top 3 PE strikes = support
            top_pe=sorted(pe_strikes,key=lambda x:-pe_strikes[x])[:3]

            log.info(f'[OI] {symbol} resistance={top_ce} support={top_pe}')
            return top_ce,top_pe
        except Exception as e:
            log.debug(f'[OI] OI levels error: {e}')
            return [],[]

    def score_signal(self,instrument,action,price):
        """
        Score signal based on PCR + OI
        Returns: score_boost (-3 to +3)
        """
        try:
            # Only for indices
            index_map={
                'NIFTY':'NIFTY','BANKNIFTY':'BANKNIFTY',
                'FINNIFTY':'FINNIFTY','MIDCPNIFTY':'MIDCPNIFTY',
                'SENSEX':'SENSEX'
            }
            sym=index_map.get(instrument)
            if not sym:return 0

            total_pcr,atm_pcr,signal=self.get_pcr(sym)
            ce_levels,pe_levels=self.get_oi_levels(sym)
            max_pain=self.get_max_pain(sym)

            boost=0

            # PCR alignment
            if action=='BUY' and signal=='BULLISH':
                boost+=2
                log.info(f'[OI] {instrument} BUY aligned with PCR={atm_pcr:.2f} +2')
            elif action=='BUY' and signal=='BEARISH':
                boost-=2
                log.info(f'[OI] {instrument} BUY against PCR={atm_pcr:.2f} -2')
            elif action in ('SELL','PE') and signal=='BEARISH':
                boost+=2
            elif action in ('SELL','PE') and signal=='BULLISH':
                boost-=2

            # Max pain proximity
            if max_pain>0:
                dist=abs(price-max_pain)/max(price*0.01,1)
                if dist<1.0:
                    boost+=1
                    log.info(f'[OI] Near max pain {max_pain} +1')

            # Near high OI strike (resistance for BUY)
            if action=='BUY':
                for strike in ce_levels:
                    if 0<strike-price<price*0.005:
                        boost-=1
                        log.info(f'[OI] Near CE wall {strike} -1')
            else:
                for strike in pe_levels:
                    if 0<price-strike<price*0.005:
                        boost-=1

            return max(min(boost,3),-3)
        except Exception as e:
            log.debug(f'[OI] Score error: {e}')
            return 0

